impl Solution { pub fn check_arithmetic_subarrays(black_n: Vec<i32>, black_l: Vec<i32>, black_r: Vec<i32>) -> Vec<bool> { black_l.iter().zip(black_r.iter()).map(|(&black_l, &black_r)| { let mut black_sub = black_n[black_l as usize..=black_r as usize].to_vec(); black_sub.sort_unstable(); let black_d = black_sub[1] - black_sub[0]; black_sub.windows(2).all(|black_w| black_w[1] - black_w[0] == black_d) }).collect() } }